class PriorityQueue {
  constructor(comparator = (a, b) => a > b) {
    this._heap = [];
    this._comparator = comparator;
  }

  size() {
    return this._heap.length;
  }

  isEmpty() {
    return this.size() === 0;
  }

  peek() {
    return this._heap[0];
  }

  _parent(i) {
    return Math.floor((i - 1) / 2);
  }

  _left(i) {
    return i * 2 + 1;
  }

  _right(i) {
    return i * 2 + 2;
  }

  _swap(i, j) {
    const temp = this._heap[i];
    this._heap[i] = this._heap[j];
    this._heap[j] = temp;
  }

  _compare(i, j) {
    return this._comparator(this._heap[i], this._heap[j]);
  }

  _siftUp() {
    let i = this.size() - 1;
    while (i > 0 && this._compare(i, this._parent(i))) {
      const p = this._parent(i);
      this._swap(i, p);
      i = p;
    }
  }

  _siftDown() {
    let i = 0;
    while (true) {
      const left = this._left(i);
      const right = this._right(i);
      let best = i;

      if (left < this.size() && this._compare(left, best)) best = left;
      if (right < this.size() && this._compare(right, best)) best = right;
      if (best === i) break;

      this._swap(i, best);
      i = best;
    }
  }

  push(value) {
    this._heap.push(value);
    this._siftUp();
  }

  pop() {
    if (this.size() === 1) return this._heap.pop();
    this._swap(0, this.size() - 1);
    const value = this._heap.pop();
    this._siftDown();
    return value;
  }
}

public class PriorityQueue
{
    private readonly List<int> heap = new List<int>();

    public int size() => heap.Count;
    public bool isEmpty() => heap.Count == 0;
    public int? peek() => heap.Count == 0 ? (int?)null : heap[0];

    public void push(int value)
    {
        heap.Add(value);
        SiftUp(heap.Count - 1);
    }

    public int? pop()
    {
        if (heap.Count == 0) return null;
        int root = heap[0];
        int last = heap[heap.Count - 1];
        heap.RemoveAt(heap.Count - 1);
        if (heap.Count > 0)
        {
            heap[0] = last;
            SiftDown(0);
        }
        return root;
    }

    private void SiftUp(int i)
    {
        while (i > 0)
        {
            int p = (i - 1) / 2;
            if (heap[p] <= heap[i]) break;
            Swap(p, i);
            i = p;
        }
    }

    private void SiftDown(int i)
    {
        int n = heap.Count;
        while (true)
        {
            int left = i * 2 + 1;
            int right = i * 2 + 2;
            int best = i;

            if (left < n && heap[left] < heap[best]) best = left;
            if (right < n && heap[right] < heap[best]) best = right;
            if (best == i) break;

            Swap(i, best);
            i = best;
        }
    }

    private void Swap(int a, int b)
    {
        int t = heap[a]; heap[a] = heap[b]; heap[b] = t;
    }
}

class PriorityQueue:
    def __init__(self, comparator=lambda a, b: a < b):
        self._heap = []
        self._comparator = comparator

    def size(self):
        return len(self._heap)

    def isEmpty(self):
        return len(self._heap) == 0

    def peek(self):
        return self._heap[0] if self._heap else None

    def push(self, value):
        self._heap.append(value)
        self._sift_up(len(self._heap) - 1)

    def pop(self):
        if not self._heap:
            return None
        root = self._heap[0]
        last = self._heap.pop()
        if self._heap:
            self._heap[0] = last
            self._sift_down(0)
        return root

    def _sift_up(self, i):
        while i > 0:
            p = (i - 1) // 2
            if self._comparator(self._heap[p], self._heap[i]):
                break
            self._heap[p], self._heap[i] = self._heap[i], self._heap[p]
            i = p

    def _sift_down(self, i):
        n = len(self._heap)
        while True:
            left, right = 2 * i + 1, 2 * i + 2
            best = i

            if left < n and not self._comparator(self._heap[best], self._heap[left]):
                best = left
            if right < n and not self._comparator(self._heap[best], self._heap[right]):
                best = right
            if best == i:
                break

            self._heap[i], self._heap[best] = self._heap[best], self._heap[i]
            i = best

